def get_season_number(year, start_month):
    if year == 2021 and start_month == 10:
        return 1
    elif year == 2023 and start_month == 1:
        return 2
    elif year == 2024 and start_month == 1:  # Assuming renewal for 2024
        return 3
    else:
        return None

# Example usage:
season = get_season_number(2023, 1)
print(season)  # Output: 2
